                parent / "passages.json",
                parent / f"{index_root.stem}_passages.jsonl",
                parent / f"{index_root.stem}_passages.json",
            ]
        )

    passages_file = None
    for p in candidate_paths:
        if p and p.is_file():
            passages_file = p
            break

    # If no passages file is found, adhere to requirement: return empty list
    if passages_file is None:
        return []

    passages: List[Dict[str, Any]] = []

    # Load passages: support both JSONL/NDJSON and plain JSON array
    if passages_file.suffix.lower() in {".jsonl", ".ndjson"}:
        with passages_file.open("r", encoding="utf-8") as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                try:
