                    passages.append(passage)
                except json.JSONDecodeError:
                    # Skip malformed lines
                    continue
    else:  # assume standard JSON
        try:
            with passages_file.open("r", encoding="utf-8") as f:
                data = json.load(f)
                # file may contain either a list of passages or an object
                # with a key like "passages"
                if isinstance(data, list):
                    passages = data
                elif isinstance(data, dict):
                    if "passages" in data and isinstance(data["passages"], list):
                        passages = data["passages"]
                    else:
                        # Fallback: no clear list -> no passages
                        passages = []
        except (json.JSONDecodeError, OSError):
            return []

    # Apply metadata criteria (AND logic, exact value match)
    if not metadata_criteria:
        # If no criteria specified, return all passages
        return passages

    def matches_criteria(passage: Dict[str, Any]) -> bool:
        metadata = passage.get("metadata", {})
        # Some formats may store metadata at top level; merge view
        if not isinstance(metadata, dict):
            metadata = {}
        combined_view = {**metadata, **{k: v for k, v in passage.items() if k != "metadata"}}
        for key, expected_value in metadata_criteria.items():
            if key not in combined_view:
                return False
            if combined_view[key] != expected_value:
                return False
        return True

    return [p for p in passages if matches_criteria(p)]
