from typing import List, Dict, Any
from leann.api import PassageManager, LeannSearcher  # noqa: F401  (LeannSearcher imported for completeness)
from pathlib import Path
import json
from collections import Counter, defaultdict


def _load_index_metadata(index_path: str) -> Any:
    """
    Internal helper to load the LEANN index metadata JSON.

    Tries a few common metadata file names next to the index path.
    Raises FileNotFoundError if none are found.
    """
    base = Path(index_path)

    candidate_files = []
    if base.is_file():
        # If a file is given, try:
        #   <given>.meta.json
        #   <given>.metadata.json
        candidate_files.append(base.with_suffix(base.suffix + ".meta.json"))
        candidate_files.append(base.with_suffix(base.suffix + ".metadata.json"))
    else:
        # If a directory is given, try:
        #   <dir>/metadata.json
        #   <dir>/index_metadata.json
        candidate_files.append(base / "metadata.json")
        candidate_files.append(base / "index_metadata.json")

    metadata_path = None
    for p in candidate_files:
        if p.is_file():
            metadata_path = p
            break

    if metadata_path is None:
        # As a last fallback, allow the user to point directly at the metadata file.
        if base.is_file():
            metadata_path = base
        else:
            raise FileNotFoundError(
                f"Could not find index metadata file for index_path={index_path!r}"
            )

    if not metadata_path.is_file():
        raise FileNotFoundError(
            f"Index metadata file not found at {str(metadata_path)!r}"
        )

    with metadata_path.open("r", encoding="utf-8") as f:
        return json.load(f)


def get_index_statistics(index_path: str) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index.

Args:
    index_path: Path to the LEANN index file

Returns:
    Dictionary containing:
    {
        "total_passages": total number of passages,
        "metadata_fields": list of unique metadata field names,
        "field_value_counts": dictionary of field value counts
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    data = _load_index_metadata(index_path)

    # Assume top-level is a list of passages or an object with "passages"
    if isinstance(data, list):
        passages = data
    else:
        passages = data.get("passages", [])

    total_passages = len(passages)

    all_fields = set()
    field_value_counts: Dict[str, Counter] = defaultdict(Counter)

    for passage in passages:
        # metadata is commonly under "metadata" or may be flat; handle both
        metadata = passage.get("metadata", passage)
        if not isinstance(metadata, dict):
            continue

        for key, value in metadata.items():
            all_fields.add(key)
            # Convert lists/dicts to string keys so Counter works consistently
            if isinstance(value, (list, dict)):
                value_key = json.dumps(value, sort_keys=True)
            else:
                value_key = str(value)
            field_value_counts[key][value_key] += 1

    # Convert Counters to plain dicts for JSON-serializable output
    field_value_counts_dict: Dict[str, Dict[str, int]] = {
        field: dict(counter) for field, counter in field_value_counts.items()
    }

    return {
        "total_passages": total_passages,
        "metadata_fields": sorted(all_fields),
        "field_value_counts": field_value_counts_dict,
    }


def analyze_index_coverage(index_path: str, required_fields: List[str]) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields.

Args:
    index_path: Path to the LEANN index file
    required_fields: List of metadata field names that should be present

Returns:
    Dictionary containing:
    {
        "coverage_percentage": percentage of passages that have all required fields,
        "field_coverage": dictionary mapping field name to coverage percentage,
        "missing_fields": list of required fields not found in any passage
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    data = _load_index_metadata(index_path)

    if isinstance(data, list):
        passages = data
    else:
        passages = data.get("passages", [])

    total_passages = len(passages)
    if total_passages == 0:
        # Avoid division by zero; all coverage is 0, and all required fields are "missing"
        return {
            "coverage_percentage": 0.0,
            "field_coverage": {field: 0.0 for field in required_fields},
            "missing_fields": list(required_fields),
        }

    field_present_counts: Dict[str, int] = {f: 0 for f in required_fields}
    passages_with_all_required = 0

    for passage in passages:
        metadata = passage.get("metadata", passage)
        if not isinstance(metadata, dict):
            continue

        has_all = True
        for field in required_fields:
            if field in metadata and metadata[field] is not None:
                field_present_counts[field] += 1
            else:
                has_all = False
        if has_all:
            passages_with_all_required += 1

    field_coverage: Dict[str, float] = {
        field: (field_present_counts[field] / total_passages) * 100.0
        for field in required_fields
    }

    missing_fields = [
        field for field in required_fields if field_present_counts[field] == 0
    ]

    coverage_percentage = (passages_with_all_required / total_passages) * 100.0

    return {
        "coverage_percentage": coverage_percentage,
        "field_coverage": field_coverage,
        "missing_fields": missing_fields,
    }

